/**
 * Draws the source onto a canvas scaled to fit within maxSize
 * and returns the result as a Blob.
 *
 * @param options - Resize configuration.
 * @returns Promise<Blob> — resized image bytes.
 */
resize(options: {
  maxSize: number;
  source: HTMLImageElement | File;
  type?: 'image/png' | 'image/jpeg' | 'image/webp';
  quality?: number;
}): Promise<Blob>

