import { Component, inject } from '@angular/core';
import { AXImageService } from '@acorex/core/image';

@Component({
  selector: 'app-upload',
  providers: [AXImageService], // or rely on app-level provider
  template: `<button type="button" (click)="fileInput.click()">Pick photo</button>
           <input #fileInput type="file" accept="image/*" hidden (change)="onFile($event)" />`,
})
export class UploadComponent {
  private imageService = inject(AXImageService);

  async onFile(event: Event) {
    const file = (event.target as HTMLInputElement).files?.[0];
    if (!file) return;

    const blob = await this.imageService.resize({
      source: file,
      maxSize: 1024,
      type: 'image/jpeg',
      quality: 0.85,
    });

    console.log('Original:', file.size, 'bytes → Resized:', blob.size, 'bytes');
  }
}

import { inject } from '@angular/core';
import { AXImageService } from '@acorex/core/image';

const imageService = inject(AXImageService);

async function compressPhoto(file: File): Promise<Blob> {
  return imageService.resize({
    source: file,
    maxSize: 800,
    type: 'image/jpeg',
    quality: 0.8,
  });
}

