import { Component, ElementRef, inject, viewChild } from '@angular/core';
import { AXImageService } from '@acorex/core/image';

@Component({
  selector: 'app-crop-preview',
  providers: [AXImageService],
  template: `
    <img #preview src="/assets/photo.jpg" alt="Source" />
    <button type="button" (click)="exportThumbnail()">Export thumbnail</button>
  `,
})
export class CropPreviewComponent {
  private imageService = inject(AXImageService);
  private preview = viewChild<ElementRef<HTMLImageElement>>('preview');

  async exportThumbnail() {
    const img = this.preview()?.nativeElement;
    if (!img?.complete) return;

    const blob = await this.imageService.resize({
      source: img,
      maxSize: 256,
      type: 'image/webp',
      quality: 0.9,
    });

    return blob;
  }
}

import { inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { AXImageService } from '@acorex/core/image';
import { AXFileService } from '@acorex/core/file';

async function uploadCompressedImage() {
  const imageService = inject(AXImageService);
  const fileService = inject(AXFileService);
  const http = inject(HttpClient);

  const [file] = await fileService.choose({ accept: 'image/*', multiple: false });
  if (!file) return;

  const blob = await imageService.resize({
    source: file,
    maxSize: 1200,
    type: 'image/webp',
    quality: 0.9,
  });

  const formData = new FormData();
  formData.append('file', blob, 'photo.webp');

  return http.post('/api/upload', formData).toPromise();
}

import { Component, inject, signal } from '@angular/core';
import { AXImageService } from '@acorex/core/image';

@Component({
  selector: 'app-avatar-upload',
  providers: [AXImageService],
  template: `
    @if (previewUrl()) {
      <img [src]="previewUrl()" alt="Preview" width="200" />
    }
  `,
})
export class AvatarUploadComponent {
  private imageService = inject(AXImageService);
  previewUrl = signal<string | null>(null);

  async handleFile(file: File) {
    const blob = await this.imageService.resize({
      source: file,
      maxSize: 256,
      type: 'image/jpeg',
      quality: 0.85,
    });

    // Preview in template
    const url = URL.createObjectURL(blob);
    this.previewUrl.set(url);

    // Convert Blob → File when you need a File object
    const resizedFile = new File([blob], 'avatar.jpg', { type: blob.type });
    return resizedFile;
  }

  ngOnDestroy() {
    const url = this.previewUrl();
    if (url) URL.revokeObjectURL(url);
  }
}

import { inject } from '@angular/core';
import { AXImageService } from '@acorex/core/image';

const MAX_AVATAR_PX = 256;
const MAX_FILE_BYTES = 100_000; // 100 KB target

async function prepareAvatar(file: File): Promise<File> {
  const imageService = inject(AXImageService);

  let quality = 0.9;
  let blob = await imageService.resize({
    source: file,
    maxSize: MAX_AVATAR_PX,
    type: 'image/jpeg',
    quality,
  });

  // Simple quality stepping until under size target
  while (blob.size > MAX_FILE_BYTES && quality > 0.3) {
    quality -= 0.1;
    blob = await imageService.resize({
      source: file,
      maxSize: MAX_AVATAR_PX,
      type: 'image/jpeg',
      quality,
    });
  }

  return new File([blob], file.name, { type: 'image/jpeg' });
}
